// ======================================================
// WooCommerce Order → Telegram Operations Notification
// الهدف:
// تحويل بيانات طلب WooCommerce إلى رسالة واضحة ومنظمة
// ترسل إلى فريق العمليات / التوصيل عبر Telegram
// ======================================================
// ======================================================
// 1) Read WooCommerce Order Data
// قراءة بيانات الطلب القادمة من WooCommerce
// ======================================================

const o = $json;


// ======================================================
// 2) Helper Functions
// أدوات تنظيف وحماية من القيم الفارغة
// ======================================================

// تنظيف أي قيمة وتحويلها إلى نص
const clean = (v) => (v ?? "").toString().trim();

// إرجاع قيمة آمنة أو fallback إذا كانت فارغة
const safe = (v, fallback = "-") => {
  const x = clean(v);
  return x.length ? x : fallback;
};


// ======================================================
// 3) Customer Information
// استخراج بيانات العميل
// ======================================================

const fullName = `${clean(o.billing?.first_name)} ${clean(o.billing?.last_name)}`.trim();

const customerName = safe(fullName);
const phone = safe(o.billing?.phone);


// ======================================================
// 4) Payment Method
// استخراج طريقة الدفع
// ======================================================

const paymentMethod = safe(
  o.payment_method_title || o.payment_method
).replace(/&amp;/g, "&");


// ======================================================
// 5) Address Selection
// اختيار عنوان الفوترة إذا كان متوفرًا
// وإذا لم يكن متوفرًا نستخدم عنوان الشحن
// ======================================================

const addrObj =
  o.billing && (o.billing.address_1 || o.billing.city || o.billing.country)
    ? o.billing
    : o.shipping || {};


// ======================================================
// 6) Address Formatting
// تنسيق العنوان في شكل واضح للعمليات والتوصيل
// ======================================================

const addressParts = [
  addrObj?.address_1,
  addrObj?.address_2,
  addrObj?.city,
  addrObj?.state,
  addrObj?.postcode,
  addrObj?.country,
]
  .map(clean)
  .filter(Boolean);

const address = addressParts.length ? addressParts.join("، ") : "-";


// ======================================================
// 7) Customer Note
// ملاحظة العميل إن وجدت
// ======================================================

const note = safe(o.customer_note);


// ======================================================
// 8) Order Items Formatting
// تحويل المنتجات داخل الطلب إلى قائمة واضحة
// ======================================================

const items = Array.isArray(o.line_items) ? o.line_items : [];

const itemsText = items.length
  ? items
      .map((item, index) => {
        const itemName = safe(item.name);
        const quantity = safe(item.quantity, "1");

        return `${index + 1}) ${itemName} × ${quantity}`;
      })
      .join("\n")
  : "-";


// ======================================================
// 9) Currency & Total Amount
// استخراج العملة والإجمالي النهائي
// ======================================================

const currency = clean(o.currency);
const total = safe(o.total);

const totalText = currency ? `${total} ${currency}` : total;


// ======================================================
// 10) Shipping Amount
// استخراج مبلغ التوصيل
// ======================================================

const shippingTotal = clean(
  o.shipping_total || o.shipping_lines?.[0]?.total || "0"
);

const shippingText = currency
  ? `${shippingTotal} ${currency}`
  : shippingTotal;


// ======================================================
// 11) Shipping Method
// استخراج اسم طريقة التوصيل
// ======================================================

const shippingMethod =
  Array.isArray(o.shipping_lines) && o.shipping_lines.length
    ? safe(
        o.shipping_lines
          .map((shipping) => shipping.method_title)
          .filter(Boolean)
          .join(" + ")
      )
    : "-";


// ======================================================
// 12) Order Reference
// رقم الطلب ومعرف الطلب
// ======================================================

const orderNo = safe(o.number || o.id);
const orderId = o.id;


// ======================================================
// 13) Telegram Message Builder
// بناء رسالة منظمة وواضحة لفريق العمليات
// ======================================================

const msg = `🧾 طلب جديد رقم: ${orderNo}

👤 الاسم: ${customerName}
📞 الجوال: ${phone}

🛒 المنتجات:
${itemsText}

💳 طريقة الدفع: ${paymentMethod}
🚚 طريقة التوصيل: ${shippingMethod}
💰 مبلغ التوصيل: ${shippingText}
💵 الإجمالي الكلي: ${totalText}

📍 العنوان:
${address}

📝 ملاحظة العميل:
${note}`;


// ======================================================
// 14) Final Output
// إرسال النص النهائي إلى Telegram Node
// مع order_id لاستخدامه في أزرار الحالة أو التحديثات
// ======================================================

return [
  {
    json: {
      order_id: orderId,
      text: msg,
    },
  },
];
